    pub fn cancel(&self, instance: &mut UserAnonymizationRequestFlowInstance) { self.0.cancel(instance) }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut UserAnonymizationRequestFlowInstance, error: impl Into<String>) { self.0.fail(instance, error) }
